async def modifierDates(self, dateDebut, dateFin):
    modifiable = await execute_reservation_method(
        self.id,
        "estModifiable",
        {}
    )
    if not modifiable:
        raise Exception("Non modifiable")

    salle = await get_salle(self.salle)

    dispo = await execute_salle_method(
        salle.id,
        "estDisponible",
        {"dateDebut": dateDebut, "dateFin": dateFin}
    )

    if not dispo:
        raise Exception("Salle non disponible")

    await update_reservation(
        self.id,
        ReservationCreate(
            dateDebut=dateDebut,
            dateFin=dateFin
        )
    )

